#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>

// Function to generate random session tokens for user authentication
char* generate_session_token() {
  // Initialize a buffer to store the generated token
  char token[17];

  // Generate a random number using rand() and srand()
  srand(time(NULL));
  int random_number = rand();

  // Convert the random number to a string using sprintf()
  sprintf(token, "%08x", random_number);

  // Return the generated token
  return token;
}